              <label htmlFor="name" className="text-xs font-bold text-slate-700 dark:text-slate-300 uppercase tracking-wider ml-1">Name</label>
              <input
                id="name"
                name="name"
                type="text"
                required
                disabled={isLoading}
                value={formState.name}
                onChange={handleChange}
                placeholder="John Doe"
